      '"use client";\n\nimport type {Key} from "@thenamespace/uikit";\n\nimport {\n  Autocomplete,\n  EmptyState,\n  Label,\n  ListBox,\n  SearchField,\n  Tag,\n  TagGroup,\n  useFilter,\n} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nexport function TagGroupSelection() {\n  const tags = [\n    {id: "react", name: "React"},\n    {id: "typescript", name: "TypeScript"},\n    {id: "javascript", name: "JavaScript"},\n    {id: "nodejs", name: "Node.js"},\n    {id: "python", name: "Python"},\n    {id: "vue", name: "Vue"},\n    {id: "angular", name: "Angular"},\n    {id: "nextjs", name: "Next.js"},\n  ];\n\n  const [selectedKeys, setSelectedKeys] = useState<Key[]>([]);\n  const {contains} = useFilter({sensitivity: "base"});\n\n  const onRemoveTags = (keys: Set<Key>) => {\n    setSelectedKeys((prev) => prev.filter((key) => !keys.has(key)));\n  };\n\n  return (\n    <Autocomplete\n      className="w-[256px]"\n      placeholder="Select tags"\n      selectionMode="multiple"\n      value={selectedKeys}\n      onChange={(keys) => setSelectedKeys(keys as Key[])}\n    >\n      <Label>Tags</Label>\n      <Autocomplete.Trigger>\n        <Autocomplete.Value>\n          {({defaultChildren, isPlaceholder, state}) => {\n            if (isPlaceholder || state.selectedItems.length === 0) {\n              return defaultChildren;\n            }\n\n            const selectedItemsKeys = state.selectedItems.map((item) => item.key);\n\n            return (\n              <TagGroup size="sm" onRemove={onRemoveTags}>\n                <TagGroup.List>\n                  {selectedItemsKeys.map((selectedItemKey) => {\n                    const tag = tags.find((t) => t.id === selectedItemKey);\n\n                    if (!tag) return null;\n\n                    return (\n                      <Tag key={tag.id} id={tag.id}>\n                        {tag.name}\n                      </Tag>\n                    );\n                  })}\n                </TagGroup.List>\n              </TagGroup>\n            );\n          }}\n        </Autocomplete.Value>\n        <Autocomplete.ClearButton />\n        <Autocomplete.Indicator />\n      </Autocomplete.Trigger>\n      <Autocomplete.Popover>\n        <Autocomplete.Filter filter={contains}>\n          <SearchField autoFocus name="search" variant="secondary">\n            <SearchField.Group>\n              <SearchField.SearchIcon />\n              <SearchField.Input placeholder="Search tags..." />\n              <SearchField.ClearButton />\n            </SearchField.Group>\n          </SearchField>\n          <ListBox renderEmptyState={() => <EmptyState>No tags found</EmptyState>}>\n            {tags.map((tag) => (\n              <ListBox.Item key={tag.id} id={tag.id} textValue={tag.name}>\n                {tag.name}\n                <ListBox.ItemIndicator />\n              </ListBox.Item>\n            ))}\n          </ListBox>\n        </Autocomplete.Filter>\n      </Autocomplete.Popover>\n    </Autocomplete>\n  );\n}\n',
