      '"use client";\n\nimport {Checkbox, CheckboxGroup} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nexport function Indeterminate() {\n  const [selected, setSelected] = useState(["coding"]);\n  const allOptions = ["coding", "design", "writing"];\n\n  return (\n    <div>\n      <Checkbox\n        isIndeterminate={selected.length > 0 && selected.length < allOptions.length}\n        isSelected={selected.length === allOptions.length}\n        name="select-all"\n        onChange={(isSelected: boolean) => {\n          setSelected(isSelected ? allOptions : []);\n        }}\n      >\n        <Checkbox.Content>\n          <Checkbox.Control>\n            <Checkbox.Indicator />\n          </Checkbox.Control>\n          Select all\n        </Checkbox.Content>\n      </Checkbox>\n      <div className="ml-6 flex flex-col gap-2">\n        <CheckboxGroup value={selected} onChange={setSelected}>\n          <Checkbox value="coding">\n            <Checkbox.Content>\n              <Checkbox.Control>\n                <Checkbox.Indicator />\n              </Checkbox.Control>\n              Coding\n            </Checkbox.Content>\n          </Checkbox>\n          <Checkbox value="design">\n            <Checkbox.Content>\n              <Checkbox.Control>\n                <Checkbox.Indicator />\n              </Checkbox.Control>\n              Design\n            </Checkbox.Content>\n          </Checkbox>\n          <Checkbox value="writing">\n            <Checkbox.Content>\n              <Checkbox.Control>\n                <Checkbox.Indicator />\n              </Checkbox.Control>\n              Writing\n            </Checkbox.Content>\n          </Checkbox>\n        </CheckboxGroup>\n      </div>\n    </div>\n  );\n}\n',
