      '"use client";\n\nimport {DateField, Description, Label} from "@thenamespace/uikit";\nimport {getLocalTimeZone, today} from "@internationalized/date";\n\nexport function Disabled() {\n  return (\n    <div className="flex flex-col gap-4">\n      <DateField isDisabled className="w-[256px]" name="date" value={today(getLocalTimeZone())}>\n        <Label>Date</Label>\n        <DateField.Group>\n          <DateField.Input>{(segment) => <DateField.Segment segment={segment} />}</DateField.Input>\n        </DateField.Group>\n        <Description>This date field is disabled</Description>\n      </DateField>\n      <DateField isDisabled className="w-[256px]" name="date-empty">\n        <Label>Date</Label>\n        <DateField.Group>\n          <DateField.Input>{(segment) => <DateField.Segment segment={segment} />}</DateField.Input>\n        </DateField.Group>\n        <Description>This date field is disabled</Description>\n      </DateField>\n    </div>\n  );\n}\n',
