  "date-field-form-example": {
    loader: () =>
      import("./date-field/form-example").then((module) => module.FormExample),
    file: "date-field/form-example.tsx",
    source:
      '"use client";\n\nimport type {DateValue} from "@internationalized/date";\n\nimport {Calendar} from "@gravity-ui/icons";\nimport {Button, DateField, Description, FieldError, Form, Label} from "@thenamespace/uikit";\nimport {getLocalTimeZone, today} from "@internationalized/date";\nimport {useState} from "react";\n\nexport function FormExample() {\n  const [value, setValue] = useState<DateValue | null>(null);\n  const [isSubmitting, setIsSubmitting] = useState(false);\n  const todayDate = today(getLocalTimeZone());\n  const isInvalid = value !== null && value.compare(todayDate) < 0;\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n\n    if (!value || isInvalid) {\n      return;\n    }\n\n    setIsSubmitting(true);\n\n    // Simulate API call\n    setTimeout(() => {\n      console.log("Date submitted:", {date: value});\n      setValue(null);\n      setIsSubmitting(false);\n    }, 1500);\n  };\n\n  return (\n    <Form className="flex w-[280px] flex-col gap-4" onSubmit={handleSubmit}>\n      <DateField\n        isRequired\n        className="w-full"\n        isInvalid={isInvalid}\n        minValue={todayDate}\n        name="date"\n        value={value}\n        onChange={setValue}\n      >\n        <Label>Appointment date</Label>\n        <DateField.Group>\n          <DateField.Prefix>\n            <Calendar className="size-4 text-muted" />\n          </DateField.Prefix>\n          <DateField.Input>{(segment) => <DateField.Segment segment={segment} />}</DateField.Input>\n        </DateField.Group>\n        {isInvalid ? (\n          <FieldError>Date must be today or in the future</FieldError>\n        ) : (\n          <Description>Enter a date from today onwards</Description>\n        )}\n      </DateField>\n      <Button\n        className="w-full"\n        isDisabled={!value || isInvalid}\n        isPending={isSubmitting}\n        type="submit"\n        variant="primary"\n      >\n        {isSubmitting ? "Submitting..." : "Submit"}\n      </Button>\n    </Form>\n  );\n}\n',
  },
