  "date-field-granularity": {
    loader: () =>
      import("./date-field/granularity").then((module) => module.Granularity),
    file: "date-field/granularity.tsx",
    source:
      '"use client";\n\nimport type {DateValue} from "@internationalized/date";\n\nimport {CircleQuestion} from "@gravity-ui/icons";\nimport {DateField, Label, ListBox, Select, Tooltip} from "@thenamespace/uikit";\nimport {parseDate, parseZonedDateTime} from "@internationalized/date";\nimport {useState} from "react";\n\nexport function Granularity() {\n  const granularityOptions = [\n    {id: "day", label: "Day"},\n    {id: "hour", label: "Hour"},\n    {id: "minute", label: "Minute"},\n    {id: "second", label: "Second"},\n  ] as const;\n\n  const [granularity, setGranularity] = useState<"day" | "hour" | "minute" | "second">("day");\n\n  // Determine appropriate default value based on granularity\n  let defaultValue: DateValue;\n\n  if (granularity === "day") {\n    defaultValue = parseDate("2025-02-03");\n  } else {\n    // hour, minute, second\n    defaultValue = parseZonedDateTime("2025-02-03T08:45:00[America/Los_Angeles]");\n  }\n\n  return (\n    <div className="flex gap-4">\n      <DateField\n        className="w-[256px]"\n        defaultValue={defaultValue}\n        granularity={granularity}\n        name="granularity-date"\n      >\n        <Label>Appointment Date</Label>\n        <DateField.Group>\n          <DateField.Input>{(segment) => <DateField.Segment segment={segment} />}</DateField.Input>\n        </DateField.Group>\n      </DateField>\n      <div className="flex flex-col gap-1">\n        <div className="flex items-center gap-2">\n          <Label>Granularity</Label>\n          <Tooltip delay={0}>\n            <Tooltip.Trigger aria-label="Granularity information">\n              <CircleQuestion className="size-4 text-muted" />\n            </Tooltip.Trigger>\n            <Tooltip.Content placement="bottom start">\n              <p>\n                Determines the smallest unit displayed in the date picker. By default, this is "day"\n                for dates, and "minute" for times.\n              </p>\n            </Tooltip.Content>\n          </Tooltip>\n        </div>\n        <Select\n          className="w-[110px]"\n          placeholder="Select granularity"\n          value={granularity}\n          variant="secondary"\n          onChange={(value) => setGranularity(value as typeof granularity)}\n        >\n          <Select.Trigger>\n            <Select.Value />\n            <Select.Indicator />\n          </Select.Trigger>\n          <Select.Popover>\n            <ListBox>\n              {granularityOptions.map((option) => (\n                <ListBox.Item key={option.id} id={option.id} textValue={option.label}>\n                  {option.label}\n                  <ListBox.ItemIndicator />\n                </ListBox.Item>\n              ))}\n            </ListBox>\n          </Select.Popover>\n        </Select>\n      </div>\n    </div>\n  );\n}\n',
  },
