  "date-picker-form-example": {
    loader: () =>
      import("./date-picker/form-example").then((module) => module.FormExample),
    file: "date-picker/form-example.tsx",
    source:
      '"use client";\n\nimport type {DateValue} from "@internationalized/date";\n\nimport {\n  Button,\n  Calendar,\n  DateField,\n  DatePicker,\n  Description,\n  FieldError,\n  Form,\n  Label,\n} from "@thenamespace/uikit";\nimport {getLocalTimeZone, today} from "@internationalized/date";\nimport {useState} from "react";\n\nexport function FormExample() {\n  const [value, setValue] = useState<DateValue | null>(null);\n  const [isSubmitting, setIsSubmitting] = useState(false);\n  const currentDate = today(getLocalTimeZone());\n  const isInvalid = value != null && value.compare(currentDate) < 0;\n\n  const handleSubmit = (event: React.FormEvent) => {\n    event.preventDefault();\n\n    if (!value || isInvalid) {\n      return;\n    }\n\n    setIsSubmitting(true);\n\n    setTimeout(() => {\n      setValue(null);\n      setIsSubmitting(false);\n    }, 1200);\n  };\n\n  return (\n    <Form className="flex w-72 flex-col gap-3" onSubmit={handleSubmit}>\n      <DatePicker\n        isRequired\n        isInvalid={isInvalid}\n        minValue={currentDate}\n        name="appointmentDate"\n        value={value}\n        onChange={setValue}\n      >\n        <Label>Appointment date</Label>\n        <DateField.Group fullWidth>\n          <DateField.Input>{(segment) => <DateField.Segment segment={segment} />}</DateField.Input>\n          <DateField.Suffix>\n            <DatePicker.Trigger>\n              <DatePicker.TriggerIndicator />\n            </DatePicker.Trigger>\n          </DateField.Suffix>\n        </DateField.Group>\n        {isInvalid ? (\n          <FieldError>Date must be today or in the future.</FieldError>\n        ) : (\n          <Description>Choose a valid appointment date.</Description>\n        )}\n        <DatePicker.Popover>\n          <Calendar aria-label="Event date">\n            <Calendar.Header>\n              <Calendar.YearPickerTrigger>\n                <Calendar.YearPickerTriggerHeading />\n                <Calendar.YearPickerTriggerIndicator />\n              </Calendar.YearPickerTrigger>\n              <Calendar.NavButton slot="previous" />\n              <Calendar.NavButton slot="next" />\n            </Calendar.Header>\n            <Calendar.Grid>\n              <Calendar.GridHeader>\n                {(day) => <Calendar.HeaderCell>{day}</Calendar.HeaderCell>}\n              </Calendar.GridHeader>\n              <Calendar.GridBody>{(date) => <Calendar.Cell date={date} />}</Calendar.GridBody>\n            </Calendar.Grid>\n            <Calendar.YearPickerGrid>\n              <Calendar.YearPickerGridBody>\n                {({year}) => <Calendar.YearPickerCell year={year} />}\n              </Calendar.YearPickerGridBody>\n            </Calendar.YearPickerGrid>\n          </Calendar>\n        </DatePicker.Popover>\n      </DatePicker>\n      <Button\n        className="w-full"\n        isDisabled={!value || isInvalid}\n        isPending={isSubmitting}\n        type="submit"\n      >\n        {isSubmitting ? "Submitting..." : "Submit"}\n      </Button>\n    </Form>\n  );\n}\n',
  },
