  "date-range-picker-form-example": {
    loader: () =>
      import("./date-range-picker/form-example").then(
        (module) => module.FormExample,
      ),
    file: "date-range-picker/form-example.tsx",
    source:
      '"use client";\n\nimport type {DateValue} from "@internationalized/date";\n\nimport {\n  Button,\n  DateField,\n  DateRangePicker,\n  Description,\n  FieldError,\n  Form,\n  Label,\n  RangeCalendar,\n} from "@thenamespace/uikit";\nimport {getLocalTimeZone, today} from "@internationalized/date";\nimport {useState} from "react";\n\ntype DateRange = {\n  start: DateValue;\n  end: DateValue;\n};\n\nexport function FormExample() {\n  const [value, setValue] = useState<DateRange | null>(null);\n  const [isSubmitting, setIsSubmitting] = useState(false);\n  const currentDate = today(getLocalTimeZone());\n  const isInvalid =\n    value != null && (value.start.compare(currentDate) < 0 || value.end.compare(value.start) < 0);\n\n  const handleSubmit = (event: React.FormEvent) => {\n    event.preventDefault();\n\n    if (!value || isInvalid) return;\n\n    setIsSubmitting(true);\n\n    setTimeout(() => {\n      setValue(null);\n      setIsSubmitting(false);\n    }, 1200);\n  };\n\n  return (\n    <Form className="flex w-80 flex-col gap-3" onSubmit={handleSubmit}>\n      <DateRangePicker\n        isRequired\n        endName="tripEndDate"\n        isInvalid={isInvalid}\n        minValue={currentDate}\n        startName="tripStartDate"\n        value={value}\n        onChange={setValue}\n      >\n        <Label>Trip dates</Label>\n        <DateField.Group fullWidth>\n          <DateField.Input slot="start">\n            {(segment) => <DateField.Segment segment={segment} />}\n          </DateField.Input>\n          <DateRangePicker.RangeSeparator />\n          <DateField.Input slot="end">\n            {(segment) => <DateField.Segment segment={segment} />}\n          </DateField.Input>\n          <DateField.Suffix>\n            <DateRangePicker.Trigger>\n              <DateRangePicker.TriggerIndicator />\n            </DateRangePicker.Trigger>\n          </DateField.Suffix>\n        </DateField.Group>\n        {isInvalid ? (\n          <FieldError>Please choose a valid range in the future.</FieldError>\n        ) : (\n          <Description>Select your check-in and check-out dates.</Description>\n        )}\n        <DateRangePicker.Popover>\n          <RangeCalendar aria-label="Trip dates">\n            <RangeCalendar.Header>\n              <RangeCalendar.YearPickerTrigger>\n                <RangeCalendar.YearPickerTriggerHeading />\n                <RangeCalendar.YearPickerTriggerIndicator />\n              </RangeCalendar.YearPickerTrigger>\n              <RangeCalendar.NavButton slot="previous" />\n              <RangeCalendar.NavButton slot="next" />\n            </RangeCalendar.Header>\n            <RangeCalendar.Grid>\n              <RangeCalendar.GridHeader>\n                {(day) => <RangeCalendar.HeaderCell>{day}</RangeCalendar.HeaderCell>}\n              </RangeCalendar.GridHeader>\n              <RangeCalendar.GridBody>\n                {(date) => <RangeCalendar.Cell date={date} />}\n              </RangeCalendar.GridBody>\n            </RangeCalendar.Grid>\n            <RangeCalendar.YearPickerGrid>\n              <RangeCalendar.YearPickerGridBody>\n                {({year}) => <RangeCalendar.YearPickerCell year={year} />}\n              </RangeCalendar.YearPickerGridBody>\n            </RangeCalendar.YearPickerGrid>\n          </RangeCalendar>\n        </DateRangePicker.Popover>\n      </DateRangePicker>\n      <Button\n        className="w-full"\n        isDisabled={!value || isInvalid}\n        isPending={isSubmitting}\n        type="submit"\n      >\n        {isSubmitting ? "Submitting..." : "Submit"}\n      </Button>\n    </Form>\n  );\n}\n',
  },
