  "list-box-virtualization": {
    loader: () =>
      import("./list-box/virtualization").then(
        (module) => module.Virtualization,
      ),
    file: "list-box/virtualization.tsx",
    source:
      '"use client";\n\nimport {Description, Label, ListBox, ListLayout, Virtualizer} from "@thenamespace/uikit";\n\ninterface User {\n  id: number;\n  name: string;\n  email: string;\n}\n\nexport function Virtualization() {\n  const firstNames = [\n    "Emma",\n    "Liam",\n    "Olivia",\n    "Noah",\n    "Ava",\n    "James",\n    "Sophia",\n    "Oliver",\n    "Isabella",\n    "Lucas",\n    "Mia",\n    "Ethan",\n    "Charlotte",\n    "Mason",\n    "Amelia",\n    "Logan",\n    "Harper",\n    "Alexander",\n    "Ella",\n    "Benjamin",\n  ];\n\n  const lastNames = [\n    "Smith",\n    "Johnson",\n    "Williams",\n    "Brown",\n    "Jones",\n    "Garcia",\n    "Miller",\n    "Davis",\n    "Rodriguez",\n    "Martinez",\n    "Anderson",\n    "Taylor",\n    "Thomas",\n    "Jackson",\n    "White",\n    "Harris",\n    "Clark",\n    "Lewis",\n    "Robinson",\n    "Walker",\n  ];\n\n  function generateUsers(n: number): User[] {\n    const users: User[] = [];\n\n    for (let i = 0; i < n; i++) {\n      const firstName = firstNames[i % firstNames.length];\n      const lastName = lastNames[Math.floor(i / firstNames.length) % lastNames.length];\n      const name = `${firstName} ${lastName}`;\n\n      users.push({\n        email: `${firstName?.toLowerCase()}.${lastName?.toLowerCase()}@acme.com`,\n        id: i + 1,\n        name,\n      });\n    }\n\n    return users;\n  }\n\n  const users = generateUsers(1000);\n\n  return (\n    <Virtualizer layout={ListLayout} layoutOptions={{rowHeight: 50}}>\n      <ListBox\n        aria-label="Virtualized list with 1000 items"\n        className="h-[400px] w-[300px] overflow-y-auto"\n        items={users}\n      >\n        {(user) => (\n          <ListBox.Item id={user.id} textValue={user.name}>\n            <div className="flex flex-col">\n              <Label>{user.name}</Label>\n              <Description>{user.email}</Description>\n            </div>\n            <ListBox.ItemIndicator />\n          </ListBox.Item>\n        )}\n      </ListBox>\n    </Virtualizer>\n  );\n}\n',
  },
