      '"use client";\n\nimport {Button, Modal, Radio, RadioGroup} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nexport function ScrollComparison() {\n  const [scroll, setScroll] = useState<"inside" | "outside">("inside");\n\n  return (\n    <div className="flex flex-col gap-4">\n      <RadioGroup\n        orientation="horizontal"\n        value={scroll}\n        onChange={(value) => setScroll(value as "inside" | "outside")}\n      >\n        <Radio value="inside">\n          <Radio.Content>\n            <Radio.Control>\n              <Radio.Indicator />\n            </Radio.Control>\n            Inside\n          </Radio.Content>\n        </Radio>\n        <Radio value="outside">\n          <Radio.Content>\n            <Radio.Control>\n              <Radio.Indicator />\n            </Radio.Control>\n            Outside\n          </Radio.Content>\n        </Radio>\n      </RadioGroup>\n\n      <Modal>\n        <Button variant="secondary">\n          Open Modal ({scroll.charAt(0).toUpperCase() + scroll.slice(1)})\n        </Button>\n        <Modal.Backdrop>\n          <Modal.Container scroll={scroll}>\n            <Modal.Dialog className="sm:max-w-[360px]">\n              <Modal.Header>\n                <Modal.Heading>\n                  Scroll: {scroll.charAt(0).toUpperCase() + scroll.slice(1)}\n                </Modal.Heading>\n                <p className="text-sm leading-5 text-muted">\n                  Compare scroll behaviors - inside keeps content scrollable within the modal,\n                  outside allows page scrolling\n                </p>\n              </Modal.Header>\n              <Modal.Body>\n                {Array.from({length: 30}).map((_, i) => (\n                  <p key={i} className="mb-3">\n                    Paragraph {i + 1}: Lorem ipsum dolor sit amet, consectetur adipiscing elit.\n                    Nullam pulvinar risus non risus hendrerit venenatis. Pellentesque sit amet\n                    hendrerit risus, sed porttitor quam.\n                  </p>\n                ))}\n              </Modal.Body>\n              <Modal.Footer>\n                <Button slot="close" variant="secondary">\n                  Cancel\n                </Button>\n                <Button slot="close">Confirm</Button>\n              </Modal.Footer>\n              <Modal.CloseTrigger />\n            </Modal.Dialog>\n          </Modal.Container>\n        </Modal.Backdrop>\n      </Modal>\n    </div>\n  );\n}\n',
