      '"use client";\n\nimport {Button, Description, FieldError, Form, Label, Radio, RadioGroup} from "@thenamespace/uikit";\nimport React from "react";\n\nexport function Validation() {\n  const [message, setMessage] = React.useState<string | null>(null);\n\n  return (\n    <Form\n      className="flex flex-col gap-4"\n      onSubmit={(e) => {\n        e.preventDefault();\n\n        const formData = new FormData(e.currentTarget);\n        const value = formData.get("plan-validation");\n\n        setMessage(`Your chosen plan is: ${value}`);\n      }}\n    >\n      <RadioGroup isRequired name="plan-validation">\n        <Label>Subscription plan</Label>\n        <Radio value="starter">\n          <Radio.Content>\n            <Radio.Control>\n              <Radio.Indicator />\n            </Radio.Control>\n            Starter\n          </Radio.Content>\n          <Description>For side projects and small teams</Description>\n        </Radio>\n        <Radio value="pro">\n          <Radio.Content>\n            <Radio.Control>\n              <Radio.Indicator />\n            </Radio.Control>\n            Pro\n          </Radio.Content>\n          <Description>Advanced reporting and analytics</Description>\n        </Radio>\n        <Radio value="teams">\n          <Radio.Content>\n            <Radio.Control>\n              <Radio.Indicator />\n            </Radio.Control>\n            Teams\n          </Radio.Content>\n          <Description>Share access with up to 10 teammates</Description>\n        </Radio>\n        <FieldError>Choose a subscription before continuing.</FieldError>\n      </RadioGroup>\n      <Button className="mt-2 w-fit" type="submit">\n        Submit\n      </Button>\n      {!!message && <p className="text-sm text-muted">{message}</p>}\n    </Form>\n  );\n}\n',
