    source:
      '"use client";\n\nimport {\n  BellFill,\n  BellSlash,\n  Check,\n  Microphone,\n  MicrophoneSlash,\n  Moon,\n  Power,\n  Sun,\n  VolumeFill,\n  VolumeSlashFill,\n} from "@gravity-ui/icons";\nimport {Switch} from "@thenamespace/uikit";\n\nexport function WithIcons() {\n  const icons = {\n    check: {\n      off: Power,\n      on: Check,\n      selectedControlClass: "bg-green-500/80",\n    },\n    darkMode: {\n      off: Moon,\n      on: Sun,\n      selectedControlClass: "",\n    },\n    microphone: {\n      off: Microphone,\n      on: MicrophoneSlash,\n      selectedControlClass: "bg-red-500/80",\n    },\n    notification: {\n      off: BellSlash,\n      on: BellFill,\n      selectedControlClass: "bg-purple-500/80",\n    },\n    volume: {\n      off: VolumeFill,\n      on: VolumeSlashFill,\n      selectedControlClass: "bg-blue-500/80",\n    },\n  };\n\n  return (\n    <div className="flex gap-3">\n      {Object.entries(icons).map(([key, value]) => (\n        <Switch key={key} defaultSelected aria-label={key} size="lg">\n          {({isSelected}) => (\n            <Switch.Content>\n              <Switch.Control className={isSelected ? value.selectedControlClass : ""}>\n                <Switch.Thumb>\n                  <Switch.Icon>\n                    {isSelected ? (\n                      <value.on className="size-3 text-inherit opacity-100" />\n                    ) : (\n                      <value.off className="size-3 text-inherit opacity-70" />\n                    )}\n                  </Switch.Icon>\n                </Switch.Thumb>\n              </Switch.Control>\n            </Switch.Content>\n          )}\n        </Switch>\n      ))}\n    </div>\n  );\n}\n',
