  "chat-attachment-composer": {
    component: "chat-attachment",
    file: "chat-attachment/composer.demo.tsx",
    loader: () =>
      import("./chat-attachment/composer.demo").then(
        (module) => module.DemoComposerExample,
      ),
    source:
      '"use client";\n\nimport { useEffect, useRef, useState } from "react";\n\nimport { ArrowUp01Icon, Attachment01Icon } from "@hugeicons/core-free-icons";\nimport { HugeiconsIcon } from "@hugeicons/react";\nimport {\n  ChatAttachment,\n  ChatAttachmentGroup,\n  ChatAttachmentInput,\n  PromptInput,\n} from "@thenamespace/uikit";\n\ninterface Attachment {\n  id: string;\n  mimeType: string;\n  name: string;\n  src?: string;\n}\n\nfunction ComposerDemo() {\n  const [attachments, setAttachments] = useState<Attachment[]>([]);\n  const refs = useRef<Attachment[]>([]);\n  useEffect(() => {\n    refs.current = attachments;\n  }, [attachments]);\n  useEffect(\n    () => () =>\n      refs.current.forEach((item) => {\n        if (item.src?.startsWith("blob:")) URL.revokeObjectURL(item.src);\n      }),\n    [],\n  );\n  const add = (files: File[]) =>\n    setAttachments((values) => [\n      ...values,\n      ...files.map((file) => ({\n        id: `${file.name}-${file.lastModified}-${crypto.randomUUID()}`,\n        mimeType: file.type,\n        name: file.name,\n        src: file.type.startsWith("image/")\n          ? URL.createObjectURL(file)\n          : undefined,\n      })),\n    ]);\n  return (\n    <div className="max-w-xl">\n      <ChatAttachmentInput onFilesSelected={add}>\n        <ChatAttachmentInput.Dropzone\n          render={(dropProps) => (\n            <PromptInput>\n              <PromptInput.Shell {...dropProps}>\n                <PromptInput.Content>\n                  {attachments.length ? (\n                    <PromptInput.Attachments>\n                      <ChatAttachmentGroup>\n                        {attachments.map((item) => (\n                          <ChatAttachment\n                            key={item.id}\n                            mimeType={item.mimeType}\n                            name={item.name}\n                            src={item.src}\n                          >\n                            <ChatAttachment.Preview />\n                            <ChatAttachment.Remove\n                              aria-label="Remove attachment"\n                              onPress={() =>\n                                setAttachments((values) =>\n                                  values.filter(\n                                    (value) => value.id !== item.id,\n                                  ),\n                                )\n                              }\n                            />\n                          </ChatAttachment>\n                        ))}\n                      </ChatAttachmentGroup>\n                    </PromptInput.Attachments>\n                  ) : null}\n                  <PromptInput.TextArea placeholder="Ask about your files..." />\n                </PromptInput.Content>\n                <PromptInput.Toolbar>\n                  <PromptInput.ToolbarStart>\n                    <ChatAttachmentInput.Trigger\n                      render={(props) => (\n                        <PromptInput.Action\n                          {...props}\n                          aria-label="Attach file"\n                          tooltip="Attach file"\n                        >\n                          <HugeiconsIcon\n                            aria-hidden\n                            icon={Attachment01Icon}\n                            strokeWidth={2}\n                          />\n                        </PromptInput.Action>\n                      )}\n                    />\n                  </PromptInput.ToolbarStart>\n                  <PromptInput.ToolbarEnd>\n                    <PromptInput.Send aria-label="Send">\n                      <HugeiconsIcon\n                        aria-hidden\n                        icon={ArrowUp01Icon}\n                        strokeWidth={2}\n                      />\n                    </PromptInput.Send>\n                  </PromptInput.ToolbarEnd>\n                </PromptInput.Toolbar>\n              </PromptInput.Shell>\n            </PromptInput>\n          )}\n        />\n      </ChatAttachmentInput>\n    </div>\n  );\n}\n\nexport const DemoComposerExample = () => <ComposerDemo />;\n',
    title: "Composer",
  },
