  "sheet-nested": {
    component: "sheet",
    file: "sheet/nested.demo.tsx",
    loader: () =>
      import("./sheet/nested.demo").then((module) => module.DemoNestedExample),
    source:
      '"use client";\n\nimport { Sheet } from "@thenamespace/uikit";\nimport { Button } from "@thenamespace/uikit/button";\n\nconst nestedHeight = "h-[320px]";\n\nfunction NestedDemo() {\n  return (\n    <Sheet>\n      <Sheet.Trigger>\n        <Button variant="secondary">Open Parent Sheet</Button>\n      </Sheet.Trigger>\n      <Sheet.Backdrop>\n        <Sheet.Content className="mx-auto max-w-[420px]">\n          <Sheet.Dialog className={nestedHeight}>\n            <Sheet.Handle />\n            <Sheet.CloseTrigger />\n            <Sheet.Header>\n              <Sheet.Heading>Parent Sheet</Sheet.Heading>\n            </Sheet.Header>\n            <Sheet.Body className="flex flex-col justify-between pb-4">\n              <p className="text-muted mb-4 text-sm">\n                This is the parent sheet. Open a nested sheet from here — the\n                parent will scale down and the child slides on top.\n              </p>\n              <Sheet.NestedRoot>\n                <Sheet.Trigger>\n                  <Button className="w-full" variant="secondary">\n                    Open Nested Sheet\n                  </Button>\n                </Sheet.Trigger>\n                <Sheet.Backdrop>\n                  <Sheet.Content className="mx-auto max-w-[420px]">\n                    <Sheet.Dialog className={nestedHeight}>\n                      <Sheet.Handle />\n                      <Sheet.CloseTrigger />\n                      <Sheet.Header>\n                        <Sheet.Heading>Nested Sheet</Sheet.Heading>\n                      </Sheet.Header>\n                      <Sheet.Body>\n                        <p className="text-muted mb-4 text-sm">\n                          This is a nested sheet that sits on top of the parent.\n                          Drag it down to dismiss and return to the parent\n                          sheet.\n                        </p>\n                        <Sheet.NestedRoot>\n                          <Sheet.Trigger>\n                            <Button className="w-full" variant="secondary">\n                              Go Deeper\n                            </Button>\n                          </Sheet.Trigger>\n                          <Sheet.Backdrop>\n                            <Sheet.Content className="mx-auto max-w-[420px]">\n                              <Sheet.Dialog className={nestedHeight}>\n                                <Sheet.Handle />\n                                <Sheet.CloseTrigger />\n                                <Sheet.Header>\n                                  <Sheet.Heading>Third Level</Sheet.Heading>\n                                </Sheet.Header>\n                                <Sheet.Body>\n                                  <p className="text-muted text-sm">\n                                    Three levels deep! Each parent sheet scales\n                                    down as the next one opens, creating a\n                                    stacking effect.\n                                  </p>\n                                </Sheet.Body>\n                                <Sheet.Footer>\n                                  <Sheet.Close>\n                                    <Button className="w-full">Close</Button>\n                                  </Sheet.Close>\n                                </Sheet.Footer>\n                              </Sheet.Dialog>\n                            </Sheet.Content>\n                          </Sheet.Backdrop>\n                        </Sheet.NestedRoot>\n                      </Sheet.Body>\n                      <Sheet.Footer>\n                        <Sheet.Close>\n                          <Button variant="secondary">Back</Button>\n                        </Sheet.Close>\n                      </Sheet.Footer>\n                    </Sheet.Dialog>\n                  </Sheet.Content>\n                </Sheet.Backdrop>\n              </Sheet.NestedRoot>\n            </Sheet.Body>\n          </Sheet.Dialog>\n        </Sheet.Content>\n      </Sheet.Backdrop>\n    </Sheet>\n  );\n}\n\nexport const DemoNestedExample = () => <NestedDemo />;\n',
    title: "Nested",
  },
